content.text:
{
  "shots": [
    {
      "shot_id": "SH03",
      "priority": "P0",
      "intent": "用陌生号码来电打断健一对小樱照片的停顿，让他接通并以一句“喂？”把照片线索连接到电话另一端。",
      "duration_sec": 5,
      "shot_type": "近景",
      "movement": "固定机位，允许极轻微稳定推近",
      "framing_focus": "首帧稳定近景，视觉中心是田中健一右膝旁亮起“陌生号码”的 KENICHI_SMARTPHONE_01，SAKURA_PHOTO_01 压在他膝前。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "手机铃声响起，健一目光从膝前照片移向手机，单手拿起并接通，将手机转向自己靠近耳侧，只说一句“喂？”，随后停住等待对方声音。",
      "emotion_intent": "平稳声音下带着警觉，手部动作克制，眼神短暂停在照片与陌生号码之间。",
      "scene_id": "EP06_SAKURA_UNKNOWN_CALL_LIVING_ROOM",
      "scene_name": "健一整理遗物的客厅",
      "dialogue": [
        {
          "speaker": "田中健一",
          "text": "喂？",
          "purpose": "接通陌生号码，开启电话悬念。",
          "source": "onscreen",
          "listener": "陌生号码来电者"
        }
      ],
      "narration": [],
      "subtitle": [
        "喂？"
      ],
      "positive_core": "首帧是健一整理遗物的客厅地板近景，黑色 KENICHI_SMARTPHONE_01 在田中健一右膝旁屏幕朝上亮起“陌生号码”，SAKURA_PHOTO_01 压在他膝前。午后纱帘光落在低饱和客厅地板上，健一穿疲惫西装坐在原位，领带略松；铃声响起后，他单手拿起手机接通，屏幕转向持有人并靠近耳侧，抬眼说“喂？”，然后保持沉默等待。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "健一整理遗物的客厅，承接上一镜的午后地板位置",
        "visual_center": "亮起来电界面“陌生号码”的 KENICHI_SMARTPHONE_01，旁边可见压在膝前的 SAKURA_PHOTO_01",
        "visible_characters": [
          "田中健一"
        ],
        "character_positions": {
          "田中健一": "画面右侧坐在地板上，上半身与右手入镜，视线落向膝旁手机"
        },
        "key_props": [
          "KENICHI_SMARTPHONE_01",
          "SAKURA_PHOTO_01"
        ],
        "speaking_state": "首帧无人说话，只有手机铃声；后段田中健一是唯一主动说话人；电话远端本镜头无声音",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推近"
      },
      "dialogue_blocking": {
        "active_speaker": "田中健一",
        "first_speaker": "田中健一",
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [],
        "lip_sync_policy": "single_active_speaker"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "medium",
        "risk_notes": "同镜包含来电提示、拿起手机和一句短对白，需保持动作微小稳定；电话远端不出声，避免同镜电话对话混杂。首帧按剧情短暂显示“陌生号码”，接通后手机屏幕朝向持有人且画面不再呈现内容。",
        "prop_library": {
          "KENICHI_SMARTPHONE_01": {
            "display_name": "健一手机",
            "count": "1部",
            "size": "约15厘米 × 7厘米 × 0.8厘米",
            "color": "黑色机身，深色保护壳",
            "material": "玻璃屏幕，金属边框，硅胶保护壳",
            "structure": "直板智能手机，来电界面可短暂显示“陌生号码”",
            "canonical_motion_policy": "通话时由健一手持，靠近耳侧或胸前；远端声音镜头中屏幕朝内，不展示额外屏幕内容。"
          },
          "SAKURA_PHOTO_01": {
            "display_name": "小樱纸质照片",
            "count": "1张",
            "size": "约10厘米 × 15厘米",
            "color": "照片正面为低饱和彩色影像，背面为微泛黄白色相纸",
            "material": "半哑光相纸",
            "structure": "单张矩形照片；正面是穿校服的十四岁女孩；背面有一行细黑色手写承诺字迹，指向小樱",
            "canonical_motion_policy": "默认由健一拿取、压在膝上、被美咲轻触、递回、最后翻到背面；始终保持1张照片。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "KENICHI_SMARTPHONE_01",
            "position": "本镜头首帧位于田中健一右膝旁，屏幕朝上亮起来电界面“陌生号码”",
            "first_frame_visible": true,
            "motion_policy": "铃响后由健一单手拿起并接通；接通时屏幕转向持有人，靠近耳侧，不呈现额外屏幕信息",
            "controlled_by": "田中健一"
          },
          {
            "prop_id": "SAKURA_PHOTO_01",
            "position": "本镜头首帧压在田中健一膝前，照片正面边缘可见，承接上一镜位置",
            "first_frame_visible": true,
            "motion_policy": "本镜头保持在膝前不翻面，不揭示背面承诺字迹",
            "controlled_by": "田中健一"
          }
        ],
        "phone_contract": {
          "holder": "田中健一",
          "screen_orientation": "screen facing inward toward holder",
          "screen_content_visible": false
        }
      },
      "source_basis": "“电话铃声响起……健一接起，屏幕显示陌生号码。‘喂？’他的声音平稳，却带着一丝警觉。”"
    }
  ],
  "qa_report": [
    {
      "check": "single shot only",
      "result": "pass",
      "notes": "仅输出 SH03，shots 数组长度为 1，duration_sec 为 5。"
    },
    {
      "check": "TARGET_FACTS alignment",
      "result": "pass",
      "notes": "包含陌生号码来电、健一拿起手机接通、说“喂？”，并保留小樱照片在膝前。"
    },
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "本镜头唯一主动说话人为田中健一；电话远端无声音；通话回复未混入本镜头。"
    },
    {
      "check": "first frame stability",
      "result": "pass",
      "notes": "首帧为同一客厅地板近景，视觉中心明确为亮起“陌生号码”的手机与膝前照片。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "使用 KENICHI_SMARTPHONE_01 与 SAKURA_PHOTO_01，并按道具库定义数量、尺寸、颜色、材质、结构和运动策略。"
    },
    {
      "check": "continuity from SH02",
      "result": "pass",
      "notes": "承接上一镜照片已在膝前的状态，不重复照片发现功能，只执行陌生号码来电与接听。"
    }
  ]
}
